"use client";

import { useState } from "react";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { signIn, getSession } from "next-auth/react";
import { useRouter, useSearchParams } from "next/navigation";
import {
  Loader2, ArrowRight, ShieldCheck,
  User, Calendar, Hash, IdCard,
} from "lucide-react";
import { toast } from "sonner";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { cn } from "@/lib/utils";
import { patientLoginSchema, hrLoginSchema } from "@/lib/validations/auth";
import type { z } from "zod";

type PatientInput = z.infer<typeof patientLoginSchema>;
type HrInput      = z.infer<typeof hrLoginSchema>;

function FieldError({ message }: { message?: string }) {
  if (!message) return null;
  return (
    <p className="text-xs text-destructive flex items-center gap-1.5 mt-1">
      <span className="w-1.5 h-1.5 rounded-full bg-destructive shrink-0" />
      {message}
    </p>
  );
}

export default function LoginPage() {
  const router     = useRouter();
  const searchParams = useSearchParams();
  const callbackUrl  = searchParams.get("callbackUrl");
  const [tab, setTab] = useState<"patient" | "hr">("patient");
  const [isLoading, setIsLoading] = useState(false);

  const patientForm = useForm<PatientInput>({
    resolver: zodResolver(patientLoginSchema),
    defaultValues: { patientCode: "", dob: "" },
  });

  const hrForm = useForm<HrInput>({
    resolver: zodResolver(hrLoginSchema),
    defaultValues: { hrCode: "", dob: "", pin: "" },
  });

  async function doSignIn(loginType: "patient" | "hr", identifier: string, dob: string, pin?: string) {
    setIsLoading(true);
    try {
      const result = await signIn("credentials", {
        loginType,
        identifier,
        dob,
        pin: pin ?? "",
        redirect: false,
      });

      if (result?.error) {
        toast.error(result.error);
        return;
      }

      if (result?.ok) {
        toast.success("Welcome back!");
        const session     = await getSession();
        const role        = (session?.user as { role?: string })?.role;
        const destination = callbackUrl
          ?? (role === "HR" || role === "ADMIN" ? "/hr/dashboard" : "/dashboard");
        router.push(destination);
        router.refresh();
      }
    } catch {
      toast.error("An unexpected error occurred. Please try again.");
    } finally {
      setIsLoading(false);
    }
  }

  const onPatientSubmit = (data: PatientInput) =>
    doSignIn("patient", data.patientCode.toUpperCase(), data.dob);

  const onHrSubmit = (data: HrInput) =>
    doSignIn("hr", data.hrCode.toUpperCase(), data.dob, data.pin);

  const inputCls = (hasError: boolean) =>
    cn(
      "pl-10 h-11 rounded-xl bg-card border-border text-foreground placeholder:text-muted-foreground/50",
      hasError
        ? "border-destructive focus-visible:ring-destructive/20"
        : "focus-visible:border-primary focus-visible:ring-primary/15"
    );

  return (
    <div className="space-y-7">

      {/* Header */}
      <div className="space-y-1.5">
        <h2 className="text-3xl font-bold text-foreground leading-tight tracking-tight">
          Welcome back
        </h2>
        <p className="text-sm text-muted-foreground">
          Sign in to access your health records
        </p>
      </div>

      {/* Tab switcher */}
      <div className="flex rounded-xl border border-border bg-muted/40 p-1 gap-1">
        <button
          type="button"
          onClick={() => setTab("patient")}
          className={cn(
            "flex-1 flex items-center justify-center gap-2 rounded-lg py-2 text-sm font-semibold transition-all",
            tab === "patient"
              ? "bg-card text-foreground shadow-sm border border-border"
              : "text-muted-foreground hover:text-foreground"
          )}
        >
          <User className="h-3.5 w-3.5" />
          Patient
        </button>
        <button
          type="button"
          onClick={() => setTab("hr")}
          className={cn(
            "flex-1 flex items-center justify-center gap-2 rounded-lg py-2 text-sm font-semibold transition-all",
            tab === "hr"
              ? "bg-violet-600 text-white shadow-sm"
              : "text-muted-foreground hover:text-foreground"
          )}
        >
          <ShieldCheck className="h-3.5 w-3.5" />
          HR Staff
        </button>
      </div>

      {/* ── PATIENT FORM ── */}
      {tab === "patient" && (
        <form onSubmit={patientForm.handleSubmit(onPatientSubmit)} className="space-y-5">

          <div className="space-y-1.5">
            <Label htmlFor="patientCode" className="text-sm font-medium">Patient ID</Label>
            <div className="relative">
              <IdCard className="absolute left-3.5 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground/50" />
              <Input
                id="patientCode"
                placeholder="e.g. PT-2024-00123"
                autoComplete="username"
                disabled={isLoading}
                {...patientForm.register("patientCode")}
                className={inputCls(!!patientForm.formState.errors.patientCode)}
              />
            </div>
            <FieldError message={patientForm.formState.errors.patientCode?.message} />
          </div>

          <div className="space-y-1.5">
            <Label htmlFor="patient-dob" className="text-sm font-medium">Date of Birth</Label>
            <div className="relative">
              <Calendar className="absolute left-3.5 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground/50" />
              <Input
                id="patient-dob"
                type="date"
                disabled={isLoading}
                {...patientForm.register("dob")}
                className={inputCls(!!patientForm.formState.errors.dob)}
              />
            </div>
            <FieldError message={patientForm.formState.errors.dob?.message} />
          </div>

          <button
            type="submit"
            disabled={isLoading}
            className="w-full h-11 rounded-xl text-sm font-semibold text-white flex items-center justify-center gap-2 transition-all disabled:opacity-60 disabled:cursor-not-allowed"
            style={{ background: "var(--gradient-primary)" }}
          >
            {isLoading ? (
              <><Loader2 className="h-4 w-4 animate-spin" />Signing in…</>
            ) : (
              <>Sign in <ArrowRight className="h-4 w-4" /></>
            )}
          </button>

          <p className="text-center text-xs text-muted-foreground">
            Your Patient ID is printed on your hospital card or visit receipt.
          </p>
        </form>
      )}

      {/* ── HR FORM ── */}
      {tab === "hr" && (
        <form onSubmit={hrForm.handleSubmit(onHrSubmit)} className="space-y-5">

          <div className="space-y-1.5">
            <Label htmlFor="hrCode" className="text-sm font-medium">HR Staff ID</Label>
            <div className="relative">
              <IdCard className="absolute left-3.5 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground/50" />
              <Input
                id="hrCode"
                placeholder="e.g. HR-2024-00001"
                autoComplete="username"
                disabled={isLoading}
                {...hrForm.register("hrCode")}
                className={inputCls(!!hrForm.formState.errors.hrCode)}
              />
            </div>
            <FieldError message={hrForm.formState.errors.hrCode?.message} />
          </div>

          <div className="space-y-1.5">
            <Label htmlFor="hr-dob" className="text-sm font-medium">Date of Birth</Label>
            <div className="relative">
              <Calendar className="absolute left-3.5 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground/50" />
              <Input
                id="hr-dob"
                type="date"
                disabled={isLoading}
                {...hrForm.register("dob")}
                className={inputCls(!!hrForm.formState.errors.dob)}
              />
            </div>
            <FieldError message={hrForm.formState.errors.dob?.message} />
          </div>

          <div className="space-y-1.5">
            <Label htmlFor="pin" className="text-sm font-medium">3-Digit PIN</Label>
            <div className="relative">
              <Hash className="absolute left-3.5 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground/50" />
              <Input
                id="pin"
                type="password"
                placeholder="• • •"
                maxLength={3}
                autoComplete="one-time-code"
                disabled={isLoading}
                {...hrForm.register("pin")}
                className={inputCls(!!hrForm.formState.errors.pin)}
              />
            </div>
            <FieldError message={hrForm.formState.errors.pin?.message} />
          </div>

          <button
            type="submit"
            disabled={isLoading}
            className="w-full h-11 rounded-xl text-sm font-semibold text-white flex items-center justify-center gap-2 transition-all disabled:opacity-60 disabled:cursor-not-allowed bg-violet-600 hover:bg-violet-700"
          >
            {isLoading ? (
              <><Loader2 className="h-4 w-4 animate-spin" />Signing in…</>
            ) : (
              <><ShieldCheck className="h-4 w-4" />HR Sign in</>
            )}
          </button>

          <p className="text-center text-xs text-muted-foreground">
            HR credentials are issued upon approved request. Contact your system administrator.
          </p>
        </form>
      )}

      {/* Trust */}
      <div className="flex items-center justify-center gap-1.5 text-xs text-muted-foreground/50">
        <ShieldCheck className="h-3.5 w-3.5" />
        <span>256-bit encrypted · HIPAA compliant</span>
      </div>
    </div>
  );
}
